import {
  isProgramError,
  type Address,
  type SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM,
  type SolanaError,
} from "gill";
import { RAFFLE_PROGRAM_ADDRESS } from "../programs";

/** RoundDoesNotExist: Round does not exist */
export const RAFFLE_ERROR__ROUND_DOES_NOT_EXIST = 0x1770; // 6000

export type RaffleError = typeof RAFFLE_ERROR__ROUND_DOES_NOT_EXIST;

let raffleErrorMessages: Record<RaffleError, string> | undefined;
if (process.env.NODE_ENV !== "production") {
  raffleErrorMessages = {
    [RAFFLE_ERROR__ROUND_DOES_NOT_EXIST]: `Round does not exist`,
  };
}

export function getRaffleErrorMessage(code: RaffleError): string {
  if (process.env.NODE_ENV !== "production") {
    return (raffleErrorMessages as Record<RaffleError, string>)[code];
  }

  return "Error message not available in production bundles.";
}

export function isRaffleError<TProgramErrorCode extends RaffleError>(
  error: unknown,
  transactionMessage: {
    instructions: Record<number, { programAddress: Address }>;
  },
  code?: TProgramErrorCode,
): error is SolanaError<typeof SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM> &
  Readonly<{ context: Readonly<{ code: TProgramErrorCode }> }> {
  return isProgramError<TProgramErrorCode>(
    error,
    transactionMessage,
    RAFFLE_PROGRAM_ADDRESS,
    code,
  );
}
